-- supabase_vault compatibility suite.
--
-- The v0.3.1 tag generates a control file with default_version=0.3.1 but ships
-- a 0.3.0 base install script plus a 0.3.0--0.3.1 upgrade. Install the base
-- version explicitly, then UPDATE, and exercise the encrypted secret APIs with
-- the deterministic getkey script generated by the harness.
CREATE EXTENSION supabase_vault VERSION '0.3.0';
ALTER EXTENSION supabase_vault UPDATE TO '0.3.1';

SELECT extversion = '0.3.1' AS ok
FROM pg_extension
WHERE extname = 'supabase_vault';

CREATE TEMP TABLE vault_secret_ids AS
SELECT vault.create_secret('s3kr3t_k3y', 'a_name', 'this is the foo secret key') AS id;

SELECT decrypted_secret = 's3kr3t_k3y'
       AND description = 'this is the foo secret key' AS ok
FROM vault.decrypted_secrets
WHERE id = (SELECT id FROM vault_secret_ids);

DO $$
BEGIN
  PERFORM vault.update_secret(
    (SELECT id FROM vault_secret_ids),
    new_name := 'a_new_name',
    new_secret := 'new_s3kr3t_k3y',
    new_description := 'this is the bar key'
  );
END
$$;

SELECT decrypted_secret = 'new_s3kr3t_k3y'
       AND name = 'a_new_name'
       AND description = 'this is the bar key' AS ok
FROM vault.decrypted_secrets
WHERE id = (SELECT id FROM vault_secret_ids);

TRUNCATE vault.secrets;

CREATE TEMP TABLE vault_empty_secret_ids AS
SELECT vault.create_secret(
  new_secret := '',
  new_name := 'empty_secret'
) AS id;

SELECT decrypted_secret = '' AS ok
FROM vault.decrypted_secrets
WHERE id = (SELECT id FROM vault_empty_secret_ids);
